3_real_world_example.code:
const isProduction = true;

// Conditionally assign different implementations
const log = isProduction
  ? function logSilent(msg) { /* suppress in prod */ }
  : function logVerbose(msg) { console.log('[DEBUG]', msg); };

log('App started'); // silent in production

// Named function expression — the name is scoped INSIDE the function only
const factorial = function fact(n) {
  return n <= 1 ? 1 : n * fact(n - 1); // 'fact' is self-referencing inside only
};
console.log(factorial(5)); // 120
// console.log(fact); //  ReferenceError — 'fact' not visible outside

6_edge_case.code:
// What if someone overwrites the outer variable?
let countdown = function go(n) {
  if (n <= 0) return 'done';
  return go(n - 1); // safe — uses internal 'go', not 'countdown'
};

const backup = countdown;
countdown = null; // overwrite outer variable

console.log(backup(3)); // 'done' — still works via internal 'go' reference
